const summary = $('Get Daily Summary').first().json;
const chartUrl = 'https://btc-oracle-production.up.railway.app/api/charts/prediction-card.png?timeframe=24h&size=twitter';

const prompt = `Write a morning Bitcoin prediction tweet. Here's the live data from BTC Seer AI:

${JSON.stringify(summary, null, 2)}

A prediction chart image is available at: ${chartUrl}
Include this URL at the end of your tweet so it shows as a preview image.

Make it engaging, vary the format (bullet points, narrative, question-style, data table). Max 270 chars (not counting the URL). Include #Bitcoin #BTC. End with 'Try @BTC_Seer_Bot'`;

return [{ json: { prompt, chartUrl } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
return [{ json: { text } }];

const tweet = $('Extract Tweet Text').first().json.text;
const now = new Date().toISOString();
console.log(`[${now}] Morning prediction tweet posted: ${tweet.substring(0, 80)}...`);
return [{ json: { status: 'posted', timestamp: now, tweet_length: tweet.length } }];
